const survives = (neighbors: number): boolean => neighbors === 2 || neighbors === 3;

const candidateDeadCells = (livingCells: readonly Cell[]): Cell[] => {
  const candidates: Cell[] = [];
  const seen = new Set<string>();
  const livingKeys = new Set(livingCells.map(([x, y]) => `${x},${y}`));
  for (const [x, y] of livingCells) {
    for (let dx = -1; dx <= 1; dx++) {
      for (let dy = -1; dy <= 1; dy++) {
        if (dx === 0 && dy === 0) continue;
        const nx = x + dx;
        const ny = y + dy;
        const key = `${nx},${ny}`;
        if (livingKeys.has(key) || seen.has(key)) continue;
        seen.add(key);
        candidates.push([nx, ny]);
      }
    }
  }
  return candidates;
};

export const nextGeneration = (livingCells: readonly Cell[]): Cell[] => {
  const survivors = livingCells.filter((cell) =>
    survives(countLivingNeighbors(cell, livingCells))
  );
  const born = candidateDeadCells(livingCells).filter(
    (cell) => countLivingNeighbors(cell, livingCells) === 3
  );
  return [...survivors, ...born];
};
